@startuml
left to right direction
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor White
  BorderColor Black
  ArrowColor Black
  FontColor Black
  FontSize 12
}

class BattleContext {
  +BattleContext()
  +getBattleOrder()
  +getTurnSystem()
  +getBattleFlow()
  +getPlayerMainTactics()
  +getPassiveProperty()
  +getBattleEvent()
  +getActiveProperty()
  +getVisualEffectContext()
}

class PlayerMainTactics {
  +PlayerMainTactics()
  +getPartySkill()
  +getPassiveSkill()
}

class Player {
  +Player()
  +getPartySkill()
  +getPassiveSkill()
}

class PassiveProperty {
  +PassiveProperty()
  +getPartySkill()
  +getPassiveSkill()
}

class BattleEvent {
  +BattleEvent()
  +getActiveEffect()
  +getPassiveEffect()
}

class ActiveProperty {
  +ActiveProperty()
  +getActiveEffect()
}

class VisualEffectContext {
  +VisualEffectContext()
  +getVisualEffect()
}

class BattleFlow {
  +BattleFlow()
  +getBattleContext()
}

class TurnSystem {
  +TurnSystem()
  +getBattleFlow()
}

class BattlerOrder {
  +BattlerOrder()
  +getBattleContext()
}

class Battler {
  +Battler()
  +getAbility()
  +getPassiveEffectManager()
  +getTargetSelection()
  +getAiInvocationContext()
  +getTurnContext()
  +getActiveTargetResult()
  +getInvocationContext()
  +getITargetable()
}

class Ability {
  +Ability()
  +getTP()
  +getAttribute()
  +getTolerance()
  +getHP()
  +getMP()
}

class TP {
  +TP()
}

class Attribute {
  +Attribute()
}

class Tolerance {
  +Tolerance()
}

class HP {
  +HP()
}

class MP {
  +MP()
}

class PassiveEffect {
  +PassiveEffect()
}

class PassiveEffectManager {
  +PassiveEffectManager()
}

class ActiveEffect {
  +ActiveEffect()
}

class BattleEventHandler {
  +BattleEventHandler()
}

class ActiveTargetRange {
  +ActiveTargetRange()
}

class ActiveTargetFilter {
  +ActiveTargetFilter()
}

class VisualEffect {
  +VisualEffect()
}

class ActiveTargetResult {
  +ActiveTargetResult()
}

class InvocationContext {
  +InvocationContext()
}

class AiInvocationContext {
  +AiInvocationContext()
}

class TurnContext {
  +TurnContext()
}

class ITargetable {
  +ITargetable()
}

class TargetSelection {
  +TargetSelection()
}

BattleContext --> BattleFlow : 1
BattleFlow --> TurnSystem : 1
TurnSystem --> BattlerOrder : 1
BattlerOrder --> BattleContext : 1

BattleContext --> PlayerMainTactics : 1
PlayerMainTactics --> Player : 1
Player --> PassiveProperty : 1
PassiveProperty --> BattleEvent : 1
BattleEvent --> ActiveProperty : 1
ActiveProperty --> VisualEffectContext : 1
VisualEffectContext --> VisualEffect : 1

BattleContext --> Battler : 1
Battler --> Ability : 1
Ability --> TP : 1
Ability --> Attribute : 1
Ability --> Tolerance : 1
Ability --> HP : 1
Ability --> MP : 1

Battler --> PassiveEffectManager : 1
PassiveEffectManager --> PassiveEffect : 1
PassiveEffect --> BattleEvent : 1
BattleEvent --> BattleEventHandler : 1
BattleEventHandler --> PassiveEffect : 1

Battler --> TargetSelection : 1
TargetSelection --> InvocationContext : 1
InvocationContext --> ActiveTargetResult : 1

Battler --> AiInvocationContext : 1
AiInvocationContext --> TurnContext : 1
TurnContext --> ActiveTargetRange : 1
ActiveTargetRange --> ActiveTargetFilter : 1
ActiveTargetFilter --> ActiveTargetResult : 1

Battler --> ITargetable : 1
ITargetable --> ActiveTargetResult : 1

@enduml
